  });
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState('');

  const save = async () => {
    setLoading(true); setErr('');
    try { await instructorAPI.updateCar(form); onSaved(); }
    catch(e) { setErr(e.response?.data?.detail || 'Ошибка'); }
    finally { setLoading(false); }
  };

  return (
    <div className={s.overlay} onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div className={s.sheet}>
        <div className={s.sheetHeader}>
          <span className={s.sheetTitle}>Автомобиль</span>
          <button className={s.sheetClose} onClick={onClose}>✕</button>
        </div>
        {[
          {key:'car_brand', lbl:'Марка автомобиля',    ph:'Lada Granta'},
          {key:'car_color', lbl:'Цвет',                ph:'Белый'},
          {key:'car_plate', lbl:'Регистрационный номер',ph:'X000XX774'},
